translations['tr']['No application server available'] = 'Kullanılabilir uygulama sunucusu yok';

translations['tr']['Protect your account with 2-step verification'] = 'Hesabınızı 2 adımlı doğrulama ile koruyun';
translations['tr']['Display the verification code using an authentication app'] = 'Kimlik doğrulama uygulamasını ayarlamak için tıklayın';
