translations['tr']['Type your phone number below, using the international phone numbers format (e.g. +14155552671):'] = 'Aşağıya uluslararası telefon numaraları formatını kullanarak telefon numaranızı girin (örneğin, +14155552671):';
translations['tr']['Enter your e-mail address below:'] = 'E-Postanız:';
translations['tr']['Click Receive SMS button to register your phone number and receive your verification code.'] = 'Telefon numaranızı kaydetmek ve doğrulama kodunuzu almak için SMS al düğmesine tıklayın.';
translations['tr']['Click Send e-mail button to register your e-mail and receive your verification code.'] = 'E-Postanızı kaydetmek ve doğrulama kodunuzu almak için E-Posta al düğmesine tıklayın.';
translations['tr']['Receive SMS'] = 'SMS al';
translations['tr']['Receive Email'] = 'E-Posta al';
translations['tr']['SMS Sent'] = 'SMS gönderildi';
translations['tr']['Email Sent'] = 'E-Posta gönderildi';
translations['tr']['Send e-mail'] = 'E-Posta gönder';
translations['tr']['Please enter a phone number'] = 'Lütfen bir telefon numarası girin';
translations['tr']['Please enter an e-mail'] = 'Lütfen bir e-posta girin';
translations['tr']['Validate your verification code'] = 'SMS,e-posta veya kimlik doğrulama uygulamanızla aldığınız doğrulama kodunu girin';
translations['tr']['Validate'] = 'Doğrula';
translations['tr']['Please enter a valid confirmation code.'] = 'Lütfen geçerli bir onay kodu girin.';
translations['tr']['An error occured while validating your 2-step verification code. Please retry or contact your administrator.'] = '2 adımlı doğrulama kodunuz kontrol edilirken bir hata oluştu. Lütfen yeniden deneyin veya yöneticinizle iletişime geçin.';
translations['tr']['An error occured while sending your 2-step verification code by SMS. Please retry or contact your administrator.'] = '2 adımlı doğrulama kodunuzun SMS ile gönderilirken bir hata oluştu. Lütfen yeniden deneyin veya yöneticinizle iletişime geçin.';
translations['tr']['An error occurred while sending your 2-step verification code by e-mail. Please retry or contact your administrator.'] = '2 adımlı doğrulama kodunuzun e-posta ile gönderilirken bir hata oluştu. Lütfen yeniden deneyin veya yöneticinizle iletişime geçin.';
translations['tr']['You are all set. From now on, you will use your authenticator app or receive your verification code by SMS or e-mail to sign in your remote session.'] = 'Her şey hazır. Bundan sonra, uzak oturumunuza giriş yapmak için kimlik doğrulama uygulamanızı kullanacaksınız veya doğrulama kodunuzu SMS veya e-posta ile alacaksınız.';
translations['tr']['Failed to send SMS verification code. Please ensure that your configured phone number is a valid phone number following E.164 format for international phone numbers (e.g. +14155552671). Otherwise, please contact your administrator.'] = 'SMS doğrulama kodu gönderilemedi. Yapılandırılmış telefon numaranızın uluslararası telefon numaraları için E.164 formatına uygun bir telefon numarası olduğundan emin olun (örneğin, +14155552671). Aksi takdirde, lütfen yöneticinizle iletişime geçin.';
translations['tr']['No QR code was generated! Please enter your credentials on the logon page.'] = 'QR kodu oluşturulmadı! Lütfen kimlik bilgilerinizi giriş sayfasına girin.';
translations['tr']['Secret key:'] = 'Gizli anahtar:';

